# ----------------------------- helper utilities ------------------------------------ #
from math import ceil
from random import choice, sample


def _required_blocks(request, replica_scheduler) -> int:
    """Return the number of KV-cache blocks the *request* will need on *replica_scheduler*."""

    # All replicas share the same block size in the current simulator.
    block_size = replica_scheduler.block_size
    return ceil(request.num_prefill_tokens / block_size)


def _prefill_backlog_tokens(replica_scheduler) -> int:
    """Compute an estimate (in tokens) of the outstanding *prefill* work on a replica."""

    backlog = 0

    # Pending requests: full prefill not started.
    for req in replica_scheduler.pending_queue:
        backlog += req.num_prefill_tokens

    # Active requests: prefill may be partially done.
    for req in replica_scheduler.active_queue:
        if not req.is_prefill_complete:
            backlog += req.num_prefill_tokens - req.num_processed_tokens

    return backlog
